  ('funbrain', 'gk', '{"text": "Who was the first Governor-General of independent India?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Lord Wavell", "C. Rajagopalachari", "Warren Hastings", "Lord Mountbatten"]'::jsonb, 3, 'Mountbatten served until June 1948; India became a republic in 1950.'),
  ('funbrain', 'gk', '{"text": "Who was the first Indian Governor-General of independent India?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Dr. Rajendra Prasad", "Jawaharlal Nehru", "C. Rajagopalachari", "Lord Mountbatten"]'::jsonb, 2, 'He succeeded Mountbatten in 1948.'),
  ('funbrain', 'gk', '{"text": "In which year did the Jallianwala Bagh massacre take place?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["1920", "1942", "1918", "1919"]'::jsonb, 3, 'General Dyer ordered firing on 13 April 1919.'),
  ('funbrain', 'gk', '{"text": "Who founded the Indian National Congress in 1885?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Dadabhai Naoroji", "Womesh Chunder Bonnerjee", "Allan Octavian Hume (A.O. Hume)", "Bal Gangadhar Tilak"]'::jsonb, 2, 'Retired ICS officer; first session Bombay.'),
