  ('funbrain', 'gk', '{"text": "Who is known as the ''Iron Man of India''?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Subhas Chandra Bose", "Jawaharlal Nehru", "Bhagat Singh", "Sardar Vallabhbhai Patel"]'::jsonb, 3, 'Unified princely states into the Indian Union.'),
  ('funbrain', 'gk', '{"text": "During which movement did Mahatma Gandhi give the slogan \"Do or Die\"?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Civil Disobedience Movement", "Non-Cooperation Movement", "Quit India Movement (1942)", "Champaran Satyagraha"]'::jsonb, 2, 'August Kranti; launched 8 August 1942.'),
