  ('funbrain', 'gk', '{"text": "The Battle of Plassey was fought in which year?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["1757", "1857", "1764", "1784"]'::jsonb, 0, 'British East India Company under Clive vs Siraj ud-Daulah.'),
