  ('funbrain', 'gk', '{"text": "Who gave the title ''Mahatma'' to Mohandas Karamchand Gandhi?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["C. F. Andrews", "Jawaharlal Nehru", "Subhas Chandra Bose", "Rabindranath Tagore"]'::jsonb, 3, 'Literary honorific meaning ''great soul''.'),
