  ('funbrain', 'gk', '{"text": "Which movement was abruptly suspended by Gandhi due to the Chauri Chaura incident?", "pack": "cbse_gk_puc100_basic"}'::jsonb, '["Khilafat Movement", "Civil Disobedience Movement", "Quit India Movement", "Non-Cooperation Movement"]'::jsonb, 3, 'Violence at Gorakhpur district, Feb 1922.'),
